import { Service } from 'typedi';
import { FindOneOptions } from 'typeorm';
import dayjs from 'dayjs';

import { HttpPaginatedResponse } from '@Libs/types/HttpPaginatedResponse';

import { CancellationType, HotelStatus, HotelSuggestType, MealPlan, UnitType } from '@Enums/Hotel';
import { FileStatus } from '@Enums/File';
import { SortDirection } from '@Enums/SortDirection';
import { PromotionType } from '@Enums/Promotion';
import { DayType } from '@Enums/Day';

import { ErrorCode } from '@Errors/ErrorCode';
import { ConflictError } from '@Errors/ConflictError';
import { NotFoundError } from '@Errors/NotFoundError';

import { Hotel } from '@Entities/Hotel';
import { Promotion } from '@Entities/Promotion';
import { Room } from '@Entities/Room';
import { Season } from '@Entities/Season';

import { HotelRepository } from '@Repositories/HotelRepository';

import { FileService } from '@Services/FileService';
import {
  CreateHotelInput,
  HotelQueryParamsInput,
  SearchHotelParamsInput,
  UpdateHotelInput,
} from '@Services/types/HotelInput';
