import { GeoWardService } from '@Services/GeoWardService';
import { SyncHotelInput } from '@Services/types/SyncHotelInput';
import { SeasonService } from '@Services/SeasonService';
import { RoomService } from '@Services/RoomService';
import { SurchargeFeeSettingService } from '@Services/SurchargeFeeSettingService';
import { PriceSettingService } from '@Services/PriceSettingService';

import { SuggestHotelItemDto, SuggestHotelResponseDto } from '@Rests/types/SuggestHotelDto';

@Service()
export class HotelService {
  constructor(
    private readonly hotelRepo: HotelRepository,
    private readonly fileService: FileService,
    private readonly amenityService: AmenityService,
    private readonly wardService: GeoWardService,
    private readonly seasonService: SeasonService,
    private readonly roomService: RoomService,
    private readonly surchargeService: SurchargeFeeSettingService,
    private readonly priceService: PriceSettingService,
  ) {}

  private generateHotelCode(id: number): string {
    // Generate code format: H + id (minimum 6 digits)
    const paddedId = id.toString().padStart(6, '0');
    return `H${paddedId}`;
  }

  async findAllPaginated(params: HotelQueryParamsInput): Promise<HttpPaginatedResponse<Hotel>> {
    const { page, size, searchText, sortBy, sortDirection, status, area, star, city, ownerId, country } = params;

    const skip = (page - 1) * size;

    const qb = this.hotelRepo
      .createQueryBuilder('hotel')
      .leftJoinAndSelect('hotel.files', 'files')
      .leftJoinAndSelect('hotel.image', 'image')
      .leftJoinAndSelect('hotel.amenities', 'amenities')
      .leftJoinAndSelect('hotel.ward', 'ward')
      .leftJoinAndSelect('ward.district', 'district')
      .leftJoinAndSelect('ward.city', 'wardCity')
      .leftJoinAndSelect('district.city', 'districtCity')
      .leftJoinAndSelect('wardCity.country', 'wardCountry')
      .leftJoinAndSelect('districtCity.country', 'districtCountry');

    if (searchText) {
      qb.andWhere('(hotel.localName ILIKE :search OR hotel.code ILIKE :search)', { search: `%${searchText}%` });
    }

    if (ownerId) {
      qb.andWhere('hotel.ownerId = :ownerId', { ownerId });
    }
    if (status) {
      qb.andWhere('hotel.status = :status', { status });
    }

    if (area) {
      qb.andWhere('hotel.area ILIKE :area', { area: `%${area}%` });
    }

    if (star) {
      qb.andWhere('hotel.star = :star', { star });
    }

    if (city) {
      qb.andWhere('(wardCity.name ILIKE :city OR districtCity.name ILIKE :city)', { city: `%${city}%` });
    }

    if (country) {
      qb.andWhere(
        '(wardCountry.name ILIKE :country OR districtCountry.name ILIKE :country OR unaccent(hotel.area) ILIKE :country)',
        {
          country: `%${country}%`,
        },
      );
    }

    qb.orderBy(`hotel.${sortBy}`, sortDirection).skip(skip).take(size);

    const [items, total] = await qb.getManyAndCount();

    return new HttpPaginatedResponse<Hotel>()
      .withItems(items)
      .withTotal(total)
      .withPage(page)
      .withSize(size)
      .withSortBy(sortBy)
      .withSortDirection(sortDirection);
  }

  findById(id: number) {
    return this.hotelRepo.findOne({ where: { id } });
  }

  async findByIdExist(id: number) {
    const entity = await this.hotelRepo.findOne({ where: { id } });
    if (!entity) throw new NotFoundError(ErrorCode.HOTEL_NOT_FOUND);
    return entity;
  }

  findWithRelations(id: number) {
    return this.hotelRepo.findWithRelations(id);
  }

  findOne(options: FindOneOptions<Hotel>) {
    return this.hotelRepo.findOne(options);
  }

  findDuplicateHotel(address: string, localName: string, globalName: string) {
    return this.hotelRepo
      .createQueryBuilder('hotel')
      .where('unaccent(hotel.address) ILIKE unaccent(:address)', { address })
      .orWhere('unaccent(hotel.localName) ILIKE unaccent(:localName)', { localName })
      .orWhere('unaccent(hotel.globalName) ILIKE unaccent(:globalName)', { globalName })
      .getOne();
  }

  async create(hotelData: CreateHotelInput) {
