    // check exist name
    const existName = await this.hotelRepo.exist({ where: { localName: hotelProps.localName } });
    if (existName) throw new ConflictError(ErrorCode.HOTEL_NAME_EXIST);

    // check exist address
    const existAddress = await this.hotelRepo.exist({ where: { address: hotelProps.address } });
    if (existAddress) throw new ConflictError(ErrorCode.HOTEL_ADDRESS_EXIST);
    const hotel = new Hotel();
    Object.assign(hotel, hotelProps);
    // query ward
    if (wardId) {
      const ward = await this.wardService.findById(wardId);
      hotel.ward = ward;
    }

    if (code) hotel.code = code;
    else {
      const nextId = (await this.hotelRepo.getCurrentId()) + 1;
      hotel.code = this.generateHotelCode(nextId);
    }

    if (files && files.length > 0) {
      hotel.files = files;
      // update files by title, description
      const existingFiles = await this.fileService.findByIds(files.map(f => f.id));
      existingFiles.forEach(ef => {
        const updatedFile = files.find(f => f.id === ef.id);
        if (updatedFile) {
          ef.title = updatedFile.title;
          ef.description = updatedFile.description;
          ef.status = FileStatus.ATTACHED;
        }
      });
      hotel.files = existingFiles;
      if (!hotel.image) hotel.image = existingFiles[0];
    }

    if (image) {
      const imageFile = await this.fileService.findById(image);
      hotel.image = imageFile;
    }

    if (amenityIds && amenityIds.length > 0) {
      const amenities = await this.amenityService.findByIds(amenityIds);
      hotel.amenities = amenities;
    }
    const createdHotel = await this.hotelRepo.save(hotel);
    // add default seasons
    await this.seasonService.defaultSeasonDay(createdHotel);

