  async update(id: number, hotelData: UpdateHotelInput) {
    const { files, amenityIds, wardId, image, ...updateRest } = hotelData;
    const hotel = await this.findById(id);
    if (!hotel) throw new NotFoundError(ErrorCode.HOTEL_NOT_FOUND);
    Object.assign(hotel, updateRest);
    if (wardId) {
      const ward = await this.wardService.findById(wardId);
      hotel.ward = ward;
    }

    if (files && files.length > 0) {
      hotel.files = files;
      // update files by title, description
      const existingFiles = await this.fileService.findByIds(files.map(f => f.id));
      existingFiles.forEach(ef => {
        const updatedFile = files.find(f => f.id === ef.id);
        if (updatedFile) {
          ef.title = updatedFile.title;
          ef.description = updatedFile.description;
          ef.status = FileStatus.ATTACHED;
        }
      });
      hotel.files = existingFiles;
    }

    if (image) {
      const imageFile = await this.fileService.findById(image);
      hotel.image = imageFile;
    }

    if (amenityIds && amenityIds.length > 0) {
      const amenities = await this.amenityService.findByIds(amenityIds);
      hotel.amenities = amenities;
    }
    await this.hotelRepo.save(hotel);
    return hotel;
  }

  delete(id: number) {
    return this.hotelRepo.delete(id);
  }

  updateStatus(id: number, status: HotelStatus) {
    return this.hotelRepo.partialUpdate(id, { status });
  }

  checkExistByCode(code: string) {
    return this.hotelRepo.findByCode(code);
  }

  async suggestHotels(
    q: string,
    cityId?: number,
    lat?: number,
    lng?: number,
    limit: number = 10,
    cursorScore?: number,
    cursorId?: number,
  ): Promise<SuggestHotelResponseDto> {
    // Add 1 to limit to check if there are more results
    const limitPlusOne = limit + 1;

    const rawResults = await this.hotelRepo.suggestHotels(q, cityId, lat, lng, limitPlusOne, cursorScore, cursorId);

    const hasMore = rawResults.length > limit;
    const items = hasMore ? rawResults.slice(0, limit) : rawResults;

    const mappedItems: SuggestHotelItemDto[] = items.map((row: any) => ({
      type: row.type as HotelSuggestType,
      id: row.id,
      title: row.title,
      subtitle: row.subtitle,
      lat: row.lat_out,
      lng: row.lng_out,
      score: row.final_score,
    }));

    const response: SuggestHotelResponseDto = {
      items: mappedItems,
      hasMore,
    };

    // Set next cursor if there are more results
    if (hasMore && mappedItems.length > 0) {
      const lastItem = mappedItems[mappedItems.length - 1];
      response.nextCursor = {
        score: lastItem.score,
        id: lastItem.id,
      };
    }

    return response;
  }

  private getBestPriceRoom(rooms: Room[], promotions: Promotion[], params: SearchHotelParamsInput): Room[] {
    return rooms.map(r => {
      r.priceSettings = r.priceSettings
        .map(ps => {
          // find promotion for price setting
          let promotion = promotions.find(p => p.rooms?.map(pr => pr.id).includes(r.id));
          ps['promotion'] = promotion || null;
          if (promotion) {
            delete promotion.rooms;
            // apply discount
            switch (promotion.type) {
              case PromotionType.ADVANCE_PURCHASE:
                const daysInAdvance = dayjs(params.checkInDate).diff(dayjs(), 'day');
                if (promotion.advancePurchase.minDaysInAdvance <= daysInAdvance) {
                  ps.price = promotion.advancePurchase.promotionalPrice
                    ? promotion.advancePurchase.promotionalPrice
                    : promotion.advancePurchase.unitType === UnitType.PERCENTAGE
                    ? Math.round(ps.price - (ps.price * promotion.advancePurchase.discountValue) / 100)
                    : ps.price - promotion.advancePurchase.discountValue;
                }
                break;

              case PromotionType.LAST_MINUTE:
                const nights = dayjs(params.checkOutDate).diff(dayjs(params.checkInDate), 'day');
                if (promotion.lastMinute.minNights <= nights) {
                  ps.price = promotion.lastMinute.promotionalPrice
                    ? promotion.lastMinute.promotionalPrice
                    : promotion.lastMinute.unitType === UnitType.PERCENTAGE
                    ? Math.round(ps.price - (ps.price * promotion.lastMinute.discountValue) / 100)
                    : ps.price - promotion.lastMinute.discountValue;
                }
                break;

              case PromotionType.STAY_PAY_FREE_NIGHT:
                const stayNights = dayjs(params.checkOutDate).diff(dayjs(params.checkInDate), 'day');
                if (promotion.stayPayFreeNight.stayNights <= stayNights) {
                  ps.price = (ps.price * promotion.stayPayFreeNight.payNights) / stayNights;
                }
                break;

              case PromotionType.WEEKEND_WEEKDAY_DEAL:
                const checkInDay = dayjs(params.checkInDate).day();
                const isWeekend = checkInDay === 0 || checkInDay === 6;
                const isDayTypeMatch = promotion.weekendWeekdayDeal.dayTypes.some(
                  dt => (isWeekend && dt === DayType.WEEKEND) || (!isWeekend && dt === DayType.WEEKDAY),
                );
                if (isDayTypeMatch) {
                  ps.price =
                    promotion.weekendWeekdayDeal.unitType === UnitType.PERCENTAGE
                      ? Math.round(ps.price - (ps.price * promotion.weekendWeekdayDeal.discountValue) / 100)
                      : ps.price - promotion.weekendWeekdayDeal.discountValue;
                }
                break;

              case PromotionType.SHOULDER_SEASON_BOOST:
                ps.price =
                  promotion.shoulderSeasonBoost.unitType === UnitType.PERCENTAGE
                    ? Math.round(ps.price - (ps.price * promotion.shoulderSeasonBoost.discountValue) / 100)
                    : ps.price - promotion.shoulderSeasonBoost.discountValue;
                break;

              case PromotionType.VALUE_ADD:
                // Value add doesn't modify price, it's a non-monetary benefit
                break;
            }
          }
          return ps;
        })
        .sort((a, b) => a.price - b.price);
      r['cheapest'] = r.priceSettings[0];
      return r;
    });
  }

