import dayjs from 'dayjs';
import { Inject, Service } from 'typedi';
import { DataSource, In } from 'typeorm';
import winston from 'winston';

import { Logger } from '@Decorators/Logger';

import { generateCode } from '@Libs/env/utils';

import { BusinessLogicError } from '@Errors/BusinessLogicError';
import { ErrorCode } from '@Errors/ErrorCode';
import { NotFoundError } from '@Errors/NotFoundError';

import { Booking } from '@Entities/Booking';
import { BookingRoom } from '@Entities/BookingRoom';
import { Customer } from '@Entities/Customer';
import { SurchargeFeeSetting } from '@Entities/SurchargeFeeSetting';

import { BookingRepository } from '@Repositories/BookingRepository';
import { CustomerRepository } from '@Repositories/CustomerRepository';
import { HotelRepository } from '@Repositories/HotelRepository';
import { RoomRepository } from '@Repositories/RoomRepository';
import { SurchargeFeeSettingRepository } from '@Repositories/SurchargeFeeSettingRepository';

import { BookingQueryParamsInput, CreateBookingInput } from '@Services/types/BookingInput';

@Service()
export class BookingService {
  constructor(
    @Logger(module) private readonly logger: winston.Logger,
    private readonly bookingRepo: BookingRepository,
    private readonly hotelRepo: HotelRepository,
    private readonly roomRepo: RoomRepository,
    private readonly customerRepo: CustomerRepository,
    private readonly surchargeFeeRepo: SurchargeFeeSettingRepository,
    @Inject('dataSource') private readonly dataSource: DataSource,
  ) {}

  /**
   * Validate booking dates
   */
  private validateBookingDates(checkInDate: Date, checkOutDate: Date) {
    const checkIn = dayjs(checkInDate);
    const checkOut = dayjs(checkOutDate);
    const today = dayjs().startOf('day');

    // Check if check-out date is after check-in date
    if (checkIn.isBefore(today) || checkOut.isBefore(checkIn) || checkOut.isSame(checkIn)) {
      throw new BusinessLogicError(ErrorCode.CHECK_IN_DATE_MUST_BE_BEFORE_CHECK_OUT_DATE);
    }
  }

  /**
   * Find existing customer by email or phone, or create new one
   */
  private async findOrCreateCustomer(
    queryRunner: any,
    customerInput: { firstName: string; lastName: string; phone?: string; email?: string },
    ownerId: string,
    createdBy: string,
  ) {
    // Try to find existing customer by email or phone
    let existingCustomer: Customer | null = null;

    if (customerInput.email) {
      existingCustomer = await queryRunner.manager.findOne(Customer, {
        where: { email: customerInput.email, ownerId },
      });
    }

    if (!existingCustomer && customerInput.phone) {
      existingCustomer = await queryRunner.manager.findOne(Customer, {
        where: { phone: customerInput.phone, ownerId },
      });
    }

    // If customer exists, return it
    if (existingCustomer) {
      return existingCustomer;
    }

    // Otherwise, create new customer
    return queryRunner.manager.save(
      Customer,
      queryRunner.manager.create(Customer, {
        ...customerInput,
        ownerId,
        createdBy,
      }),
    );
  }

  /**
   * Create a new booking with rooms and customers in a transaction
   */
  async create(input: CreateBookingInput) {
    // Validate dates for each room
    for (const room of input.rooms) {
      this.validateBookingDates(room.checkInDate, room.checkOutDate);
    }

    // 1. Validate và load tất cả rooms với hotel relation
    const roomIds = input.rooms.map(r => r.roomId);
    const rooms = await this.roomRepo.find({
      where: { id: In(roomIds) },
      relations: ['hotel'],
    });

    if (rooms.length !== roomIds.length) {
      throw new NotFoundError(ErrorCode.ROOM_NOT_FOUND);
    }

    // 2. Tạo map để tra cứu room theo ID
    const roomMap = new Map(rooms.map(room => [room.id, room]));

    // 3. Validate và load surcharge fees với hotel relation
    const allSurchargeFeeIds = input.rooms
      .filter(r => r.surchargeFees?.length)
      .flatMap(r => r.surchargeFees!.map(sf => sf.surchargeFeeId));

    const surchargeFeeMap = new Map<number, SurchargeFeeSetting>();

    if (allSurchargeFeeIds.length > 0) {
      const uniqueSurchargeFeeIds = [...new Set(allSurchargeFeeIds)];
      const surchargeFees = await this.surchargeFeeRepo.find({
        where: { id: In(uniqueSurchargeFeeIds) },
        relations: ['hotel'],
      });

      if (surchargeFees.length !== uniqueSurchargeFeeIds.length) {
