@Service()
export abstract class BaseOrmRepository<E extends ObjectLiteral> {
  protected repo: Repository<E>;
  protected dataSource: DataSource;

  constructor(dataSource: DataSource, target: EntityTarget<E>) {
    this.repo = dataSource.getRepository<E>(target);
    this.dataSource = dataSource;
  }

  findAndCount(options?: FindManyOptions<E>) {
    return this.repo.findAndCount(options);
  }

  count(options?: FindManyOptions<E>) {
    return this.repo.count(options);
  }

  exist(options?: FindManyOptions<E>) {
    return this.repo.exist(options);
  }

  find(options?: FindManyOptions<E> | undefined) {
    return this.repo.find(options);
  }

  findOne(options: FindOneOptions<E>) {
    return this.repo.findOne(options);
  }

  async save(input: DeepPartial<E>) {
    const entity = this.repo.save(input);
    return entity;
  }

  async saveMany(input: DeepPartial<E>[]) {
    const entity = this.repo.save(input);
    return entity;
  }

  async insert(input: DeepPartial<E>) {
    const entity = this.repo.create(input);
    await this.repo.insert(entity);
    return entity;
  }

  async insertMany(input: DeepPartial<E>[]) {
    const entity = this.repo.create(input);
    await this.repo.insert(entity);
    return entity;
  }

  async getNextId(): Promise<number> {
    const result = await this.repo.query(`SELECT nextval('${env.db.schema}.${this.repo.metadata.tableName}_id_seq');`);
    return parseInt(result[0].nextval, 10);
  }

  async getCurrentId(): Promise<number> {
    const seqName = `${this.repo.metadata.tableName}_id_seq`;
    const result = await this.repo.query(`
    SELECT last_value
    FROM ${env.db.schema}."${seqName}";
  `);

    return Number(result[0].last_value);
  }

  async findById(id: any, options?: FindOneOptions<E>) {
    return this.repo.findOne({ where: { id }, ...options });
  }

  async upsert(data: E) {
    return this.repo.save(data);
  }

  async delete(id: number | string) {
    return this.repo.delete(id);
  }

  async updateById(id: number, data: DeepPartial<E>): Promise<void> {
    await this.repo.update({ id } as any, data as any);
  }

  partialUpdate(id: number, partial: Partial<E>) {
    return this.repo.createQueryBuilder().update(partial).where({ id }).execute();
  }

  createQueryBuilder(alias: string) {
    return this.repo.createQueryBuilder(alias);
  }
}

