import { RoomRepository } from '@Repositories/RoomRepository';

import { AmenityService } from '@Services/AmenityService';
import { FileService } from '@Services/FileService';
import { CreateRoomInput, RoomQueryParamsInput, UpdateRoomInput } from '@Services/types/RoomInput';

@Service()
export class RoomService {
  constructor(
    private readonly roomRepo: RoomRepository,
    private readonly hotelRepo: HotelRepository,
    private readonly fileService: FileService,
    private readonly amenityService: AmenityService,
  ) {}

  private generateRoomCode(id: number): string {
    // Generate code format: R + id (minimum 6 digits)
    const paddedId = id.toString().padStart(6, '0');
    return `R${paddedId}`;
  }

  async findAllPaginated(params: RoomQueryParamsInput): Promise<HttpPaginatedResponse<Room>> {
    const { page = 1, size = 10, searchText: search, sortBy, sortDirection, hotelId, ownerId } = params;

    const skip = (page - 1) * size;

    const qb = this.roomRepo
      .createQueryBuilder('room')
      .leftJoinAndSelect('room.files', 'files')
      .leftJoinAndSelect('room.amenities', 'amenities')
      .leftJoinAndSelect('room.hotel', 'hotel');

    if (search) {
      qb.andWhere('(room.localName ILIKE :search OR room.code ILIKE :search)', { search: `%${search}%` });
    }

    if (hotelId) {
      qb.andWhere('room.hotelId = :hotelId', { hotelId });
    }

    if (ownerId) {
      qb.andWhere('room.ownerId = :ownerId', { ownerId });
    }

    qb.orderBy(`room.${sortBy}`, sortDirection).skip(skip).take(size);

    const [items, total] = await qb.getManyAndCount();

    return new HttpPaginatedResponse<Room>()
      .withItems(items)
      .withTotal(total)
      .withPage(page)
      .withSize(size)
      .withSortBy(sortBy)
      .withSortDirection(sortDirection);
  }

  findAll() {
    return this.roomRepo.find();
  }

  async findById(id: number) {
    const room = await this.roomRepo.findOne({ where: { id }, relations: ['files', 'amenities', 'hotel'] });
    if (!room) throw new NotFoundError(ErrorCode.ROOM_NOT_FOUND);
    return room;
  }

  findByHotel(hotelId: number) {
    return this.roomRepo.findByHotel(hotelId);
  }

  findAvailableRooms(hotelId: number) {
    return this.roomRepo.findAvailableRooms(hotelId);
  }

  async create(roomData: CreateRoomInput) {
    const { files, code, amenityIds, hotelId, ...roomProps } = roomData;
    // query hotel
    const hotel = await this.hotelRepo.findOne({ where: { id: hotelId } });
    if (!hotel) {
      throw new NotFoundError(ErrorCode.HOTEL_NOT_FOUND);
    }
    const room = new Room();
    Object.assign(room, roomProps);
    room.hotel = hotel;
    if (code) room.code = code;
    else {
      const nextId = (await this.roomRepo.getCurrentId()) + 1;
      room.code = this.generateRoomCode(nextId);
    }

    if (files && files.length > 0) {
      room.files = files;
      // update files by title, description
      const existingFiles = await this.fileService.findByIds(files.map(f => f.id));
      existingFiles.forEach(ef => {
        const updatedFile = files.find(f => f.id === ef.id);
        if (updatedFile) {
          ef.title = updatedFile.title;
          ef.description = updatedFile.description;
          ef.status = FileStatus.ATTACHED;
        }
      });
      room.files = existingFiles;
    }

    if (amenityIds && amenityIds.length > 0) {
      const amenities = await this.amenityService.findByIds(amenityIds);
      room.amenities = amenities;
    }
    room.maxCapacity = room.maxAdultCapacity + room.maxChildrenCapacity;
    const createdRoom = await this.roomRepo.save(room);
    return createdRoom;
  }

  async update(id: number, roomData: UpdateRoomInput) {
    const { files, amenityIds, ...updateRest } = roomData;
    const room = await this.findById(id);
    if (!room) throw new NotFoundError(ErrorCode.ROOM_NOT_FOUND);

    Object.assign(room, updateRest);

    if (files && files.length > 0) {
      room.files = files;
      // update files by title, description
      const existingFiles = await this.fileService.findByIds(files.map(f => f.id));
      existingFiles.forEach(ef => {
        const updatedFile = files.find(f => f.id === ef.id);
        if (updatedFile) {
          ef.title = updatedFile.title;
          ef.description = updatedFile.description;
          ef.status = FileStatus.ATTACHED;
        }
      });
      room.files = existingFiles;
    }

    if (amenityIds && amenityIds.length > 0) {
      const amenities = await this.amenityService.findByIds(amenityIds);
      room.amenities = amenities;
    }
    if (updateRest.extraBedType === null) {
      room.maxExtraBeds = 0;
    }
    let maxAdultCapacity = room.maxAdultCapacity || 0;
    let maxChildrenCapacity = room.maxChildrenCapacity || 0;
    if (updateRest.maxAdultCapacity) maxAdultCapacity = updateRest.maxAdultCapacity;
    if (updateRest.maxChildrenCapacity) maxChildrenCapacity = updateRest.maxChildrenCapacity;
    room.maxCapacity = maxAdultCapacity + maxChildrenCapacity;
    await this.roomRepo.save(room);
    return room;
  }

  delete(id: number) {
    return this.roomRepo.delete(id);
  }

  async checkExistByCode(code: string) {
    return this.roomRepo.findOne({ where: { code } });
  }

  async exist(options?: FindManyOptions<Room>) {
    return this.roomRepo.exist(options);
  }

  findByIds(ids: number[]) {
    return this.roomRepo.find({ where: { id: In(ids) } });
  }
  async insertMany(roomsInput: CreateRoomInput[], hotel?: Hotel) {
    const priceSettings = [];
    for (const rInput of roomsInput) {
      const { prices, ...rest } = rInput;
      const room = new Room();
      Object.assign(room, rest);
      const nextId = (await this.roomRepo.getCurrentId()) + 1;
      room.id = nextId;
      room.code = this.generateRoomCode(nextId);
      room.maxCapacity = room.maxAdultCapacity + room.maxChildrenCapacity;
      if (hotel) room.hotel = hotel;

      const roomSaved = await this.roomRepo.insert(room);

      if (prices && prices.length > 0)
        priceSettings.push(
          ...prices.map(p => ({ ...p, room: roomSaved, createdBy: rInput.createdBy, ownerId: rInput.ownerId, hotel })),
        );
    }
    return priceSettings;
  }
}

