import { Service } from 'typedi';
import { DeepPartial, FindManyOptions, FindOptionsWhere, ILike, In } from 'typeorm';

import { HttpPaginatedResponse } from '@Libs/types/HttpPaginatedResponse';
import { env } from '@Libs/env';

import { FileStatus } from '@Enums/File';

import { NotFoundError } from '@Errors/NotFoundError';
import { ErrorCode } from '@Errors/ErrorCode';
import { BasicError } from '@Errors/BasicError';

import { File } from '@Entities/File';

import { FileRepository } from '@Repositories/FileRepository';
import { HotelRepository } from '@Repositories/HotelRepository';
import { RoomRepository } from '@Repositories/RoomRepository';

import { FileInterface } from '@Services/types/FileInterface';
import { S3Service } from '@Services/S3Service';
import { CreateFileParams, UpdateFileMetadataInput } from '@Services/types/FileInput';

import { FileQueryParams } from '@Rests/types/FileQueryParams';

@Service()
export class FileService {
  constructor(
    private readonly fileRepo: FileRepository,
    private readonly s3Service: S3Service,
    private readonly hotelRepo: HotelRepository,
    private readonly roomRepo: RoomRepository,
  ) {}

  private async createFileRecord(params: CreateFileParams): Promise<File> {
    const file = new File();
    Object.assign(file, {
      ...params,
      status: FileStatus.PENDING,
    });

    return this.fileRepo.insert(file);
  }

  async findAllPaginated(params: FileQueryParams): Promise<HttpPaginatedResponse<File>> {
    const { page = 1, size = 10, searchText: search, sortBy, sortDirection, extension, mimeType, ownerId } = params;

    const skip = (page - 1) * size;
    const where: FindOptionsWhere<File> = {};

    if (search) {
      where.name = ILike(`%${search}%`);
    }

    if (extension) {
      where.extension = extension;
    }

    if (mimeType) {
      where.mimeType = ILike(`%${mimeType}%`);
    }

    if (ownerId) {
      where.ownerId = ownerId;
    }

    const options: FindManyOptions<File> = {
      where,
      skip,
      take: size,
      order: {
        [sortBy]: sortDirection,
      },
    };

    const [items, total] = await this.fileRepo.findAndCount(options);

    return new HttpPaginatedResponse<File>().withItems(items).withTotal(total).withPage(page).withSize(size);
  }

  findById(id: number) {
    return this.fileRepo.findOne({ where: { id } });
  }

  findByIds(ids: number[]) {
    return this.fileRepo.find({ where: { id: In(ids) } });
  }

  async uploadFile(file: FileInterface, ownerId: string, uploadBy: string): Promise<File> {
    const response = await this.s3Service.upload(
      file.buffer,
      env.s3.defaultBucket,
      ownerId,
      undefined,
      file.mimetype,
      'public-read',
    );
    const url = `${env.s3.cdnEndpoint}/${response.Key}`;
    const newFile = new File();
    newFile.name = file.originalname;
    newFile.path = url;
    newFile.fileUrl = url;
    newFile.size = file.size;
    newFile.mimeType = file.mimetype;
    newFile.extension = file.originalname.split('.').pop() || '';
    newFile.status = FileStatus.PENDING;
    newFile.storageKey = response.Key;
    newFile.ownerId = ownerId;
    newFile.createdBy = uploadBy;
    newFile.updatedBy = uploadBy;
    const newFileRecord = await this.createFileRecord(newFile);
    return newFileRecord;
  }

  async uploadFiles(files: FileInterface[], ownerId: string, uploadBy: string): Promise<File[]> {
    const validFiles = files.filter(file => file != null);
    if (!files || files.length === 0 || validFiles.length === 0) {
      throw new BasicError(ErrorCode.MIN_FILES_REQUIRED);
    }

    const uploadedFiles: File[] = [];
    for (const file of validFiles) {
      const temp = await this.uploadFile(file, ownerId, uploadBy);
      uploadedFiles.push(temp);
    }
    return uploadedFiles;
  }

  async updateFileMetadata(id: number, params: UpdateFileMetadataInput, ownerId?: string): Promise<File> {
    if (ownerId) {
      const file = await this.findById(id);
      if (!file || file.ownerId !== ownerId) {
        throw new NotFoundError(ErrorCode.FILE_NOT_FOUND, id);
      }
    }

    await this.fileRepo.updateById(id, params);
    return this.findById(id);
  }

  async update(id: number, fileData: DeepPartial<File>) {
    await this.fileRepo.updateById(id, fileData);
    return this.findById(id);
  }

  async delete(id: number) {
    // Check if file exists
    const file = await this.findById(id);
    if (!file) {
      throw new NotFoundError(ErrorCode.FILE_NOT_FOUND, id);
    }

    const hotelWithFile = await this.hotelRepo
      .createQueryBuilder('hotel')
      .leftJoinAndSelect('hotel.files', 'files')
      .where('files.id = :fileId', { fileId: id })
      .getOne();

    if (hotelWithFile) {
      throw new BasicError(ErrorCode.FILE_IS_USED_IN_HOTEL);
    }

    const roomWithFile = await this.roomRepo
      .createQueryBuilder('room')
      .leftJoinAndSelect('room.files', 'files')
      .where('files.id = :fileId', { fileId: id })
      .getOne();

    if (roomWithFile) {
      throw new BasicError(ErrorCode.FILE_IS_USED_IN_ROOM);
    }
    // TODO: handle S3 file deletion if necessary
    return this.fileRepo.delete(id);
  }
}

